from agent import *from models.products import *def process_page(data, context, session):   for u in data.xpath('//div[@class="entry-content"]/h2/following-sibling::ul[1]/li/a[not(contains(@href,"discontinued"))]'):       url = u.xpath('@href').string()       session.queue(Request(url), process_post, dict(context, rUrl=url) )        def process_post(data, context, session):    rTitle = data.xpath('//div[@id="content"]//h1[@class="entry-title"]/text()').string()    pCategory = "GPS"#    date = data.xpath('//span[@class="date published time"]/text()').string(multiple=True)    author = data.xpath('//a[@rel="author"]/text()').string()    aUrl = data.xpath('//a[@rel="author"]/@href').string()    pName = rTitle.split(" review")[0]    excerpt = data.xpath('/descendant::div[@id="content"][1]/descendant::p[string-length(normalize-space(.))>100][not(regexp:test(.,"UPDATE"))][1]//text()').string(multiple=True)    review = Review()    review.title = rTitle    review.ssid = review.title    review.date = date    review.type = "pro" #site's authors...    review.authors.append(Person(name=author,ssid=author,url=aUrl))    review.properties.append(ReviewProperty(type="excerpt", value=excerpt))    review.url = context['rUrl']    pr = Product(name=pName, ssid=review.ssid, url=review.url)    pr.reviews.append(review)#    pr.manufacturer = "unknown"    pr.category = pCategory    for i in data.xpath('/descendant::div[@class="entry-content"][1]//img[contains(@src,"wp-content/uploads")]'):        imUrl = i.xpath('@src').string()        imAlt = i.xpath('@alt').string()        pr.properties.append(ProductProperty(type="image", value = { 'src': imUrl, 'alt': imAlt or ''}))     session.emit(pr) def run(context, session):   session.queue(Request('http://gpstracklog.com/our-gps-reviews'), process_page, {})